#!/bin/bash
# SubagentStop hook: Checks rule violations.
# Generated by buddyx-forge.

INPUT=$(cat)
if ! command -v jq &>/dev/null; then
  exit 0
fi
AGENT_TYPE=$(echo "$INPUT" | jq -r '.agent_type // empty' 2>/dev/null)
AGENT_TYPE=$(echo "$AGENT_TYPE" | tr -cd 'a-zA-Z0-9-')
PROJECT_DIR="$(git rev-parse --show-toplevel 2>/dev/null || pwd)"
DASHBOARD_DIR="${PROJECT_DIR}/.claude/dashboard"

if ! echo "$AGENT_TYPE" | grep -q "^myapp-"; then
  exit 0
fi

VIOLATIONS=0
VIOLATION_LIST=""
CHANGED_FILES=$(git -C "$PROJECT_DIR" diff --name-only 2>/dev/null)
FRAMEWORK="laravel"

# Check: No $guarded = [] (PHP/Laravel only)
if [ "$FRAMEWORK" = "laravel" ] && [ -n "$CHANGED_FILES" ]; then
  GUARDED=$(echo "$CHANGED_FILES" | while IFS= read -r file; do
    [ -n "$file" ] && [ -f "$PROJECT_DIR/$file" ] && grep -l '\$guarded\s*=\s*\[\s*\]' "$PROJECT_DIR/$file" 2>/dev/null
  done)
  if [ -n "$GUARDED" ]; then
    VIOLATIONS=$((VIOLATIONS + 1))
    VIOLATION_LIST="${VIOLATION_LIST}guarded-empty,"
  fi
fi

# Check: No addslashes (PHP/Laravel only)
if [ "$FRAMEWORK" = "laravel" ] && [ -n "$CHANGED_FILES" ]; then
  ADDSLASHES=$(echo "$CHANGED_FILES" | while IFS= read -r file; do
    [ -n "$file" ] && [ -f "$PROJECT_DIR/$file" ] && grep -l 'addslashes' "$PROJECT_DIR/$file" 2>/dev/null
  done)
  if [ -n "$ADDSLASHES" ]; then
    VIOLATIONS=$((VIOLATIONS + 1))
    VIOLATION_LIST="${VIOLATION_LIST}addslashes,"
  fi
fi

RESULT="PASS"
if [ $VIOLATIONS -gt 0 ]; then
  RESULT="FAIL"
  AGENT_MEMORY="${PROJECT_DIR}/.claude/agent-memory/${AGENT_TYPE}/MEMORY.md"
  if [ -f "$AGENT_MEMORY" ]; then
    echo "" >> "$AGENT_MEMORY"
    echo "[$(date +%Y-%m-%d)] VIOLATION: ${VIOLATION_LIST%,}" >> "$AGENT_MEMORY"
  fi
fi

TIMESTAMP=$(date -Iseconds)
echo "{\"time\":\"${TIMESTAMP}\",\"agent\":\"${AGENT_TYPE}\",\"event\":\"VALIDATE\",\"result\":\"${RESULT}\",\"violations\":${VIOLATIONS}}" >> "${DASHBOARD_DIR}/events.jsonl"

exit 0
